import*as React from"react";import{animate}from"../../lib/animate.js";import{cubicBezier}from"../../lib/fx.js";import{ANIMATION_DURATION}from"./constants.js";const TIMING_FUNCTION=cubicBezier(.8,1);function useSlideAnimation(){const t=React.useRef([]);return{animationInQueue:function(){return!!t.current.length},getAnimateFunction:function(n){return()=>{animate({duration:ANIMATION_DURATION,timing:TIMING_FUNCTION,animationQueue:t.current,draw:n})}},addToAnimationQueue:function(n){t.current.push(n)},startAnimation:function(){1===t.current.length&&t.current[0]()}}}export{useSlideAnimation};